// Calculate P&L summary from wallet positions
const positions = $input.all();
const now = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

if (positions.length === 0 || !positions[0].json.market) {
  return [{
    json: {
      digest: `Portfolio Digest -- ${now}\n\nNo open positions found.`
    }
  }];
}

let totalValue = 0;
let totalCost = 0;
const posDetails = [];

for (const item of positions) {
  const p = item.json;
  const size = Number(p.size || p.amount || 0);
  const avgPrice = Number(p.avgPrice || p.averagePrice || p.price || 0);
  const currentPrice = Number(p.currentPrice || p.curPrice || avgPrice);
  const value = size * currentPrice;
  const cost = size * avgPrice;
  const pnl = value - cost;
  const pnlPct = cost > 0 ? (pnl / cost) * 100 : 0;

  totalValue += value;
  totalCost += cost;

  posDetails.push({
    market: p.market || p.question || p.title || 'Unknown',
    outcome: p.outcome || 'N/A',
    size,
    avgPrice,
    currentPrice,
    value,
    pnl,
    pnlPct
  });
}

// Sort by P&L for top gainers/losers
const sorted = [...posDetails].sort((a, b) => b.pnl - a.pnl);
const topGainers = sorted.filter(p => p.pnl > 0).slice(0, 3);
const topLosers = sorted.filter(p => p.pnl < 0).slice(-3).reverse();

const totalPnl = totalValue - totalCost;
const totalPnlPct = totalCost > 0 ? (totalPnl / totalCost * 100).toFixed(1) : '0.0';

let digest = `Portfolio Digest -- ${now}\n\n`;
digest += `Total Value: $${totalValue.toFixed(2)}\n`;
digest += `Total P&L: ${totalPnl >= 0 ? '+' : ''}$${totalPnl.toFixed(2)} (${totalPnlPct}%)\n`;
digest += `Open Positions: ${posDetails.length}\n`;
digest += `\n---\n`;

if (topGainers.length > 0) {
  digest += `\nTop Gainers:\n`;
  for (const g of topGainers) {
    digest += `  +$${g.pnl.toFixed(2)} (${g.pnlPct.toFixed(1)}%) -- ${g.market} [${g.outcome}]\n`;
  }
}

if (topLosers.length > 0) {
  digest += `\nTop Losers:\n`;
  for (const l of topLosers) {
    digest += `  -$${Math.abs(l.pnl).toFixed(2)} (${l.pnlPct.toFixed(1)}%) -- ${l.market} [${l.outcome}]\n`;
  }
}

digest += `\n---\nAll Positions:\n`;
for (const p of posDetails) {
  const arrow = p.pnl >= 0 ? '+' : '';
  digest += `  ${p.market} [${p.outcome}]: ${p.size} shares @ $${p.currentPrice.toFixed(3)} | P&L: ${arrow}$${p.pnl.toFixed(2)}\n`;
}

return [{ json: { digest } }];
